selector_to_html = {"a[href=\"#modelo-conformable-con-alpha-to-1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\alpha \\to 1\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-alpha-to-1\" title=\"Link to this heading\">#</a></h2><p>Establecemos <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span> en un valor extremadamente cercano a 1 (<span class=\"math notranslate nohighlight\">\\(0.99999\\)</span>) y comparamos el resultado con el modelo cl\u00e1sico. La diferencia deber\u00eda ser m\u00ednima, lo que confirma que la implementaci\u00f3n conformable es correcta.</p>", "a[href=\"#equation-1f86d09e-2872-4887-8605-7ff326e63c02\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-1f86d09e-2872-4887-8605-7ff326e63c02\">\n\\[\\begin{equation}\n m\\lambda^2 + c\\lambda + k = 0,\n\\end{equation}\\]</div>", "a[href=\"#equation-06ebb612-6604-4e66-ba55-6f6fc7bd8b09\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-06ebb612-6604-4e66-ba55-6f6fc7bd8b09\">\n\\[\\begin{equation}\n \\omega_d = \\omega_n\\sqrt{1-\\zeta^2} \\quad \\text{(para } \\zeta &lt; 1\\text{)}.\n\\end{equation}\\]</div>", "a[href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Superposici\u00f3n del modelo cl\u00e1sico y el modelo conformable<a class=\"headerlink\" href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\" title=\"Link to this heading\">#</a></h2><p>Con un valor de <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span>, el modelo conformable replica el comportamiento que presentar\u00eda el modelo cl\u00e1sico. Para profundizar en la validaci\u00f3n del modelo, es preciso considerar tambi\u00e9n la inclusi\u00f3n de la variable <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span>. Esto es</p>", "a[href=\"#equation-9a670473-fae4-4f2f-a70e-6a54ca7d7403\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-9a670473-fae4-4f2f-a70e-6a54ca7d7403\">\n\\[\\begin{equation}\n x(t) = e^{-\\zeta\\omega_n t}\\left[A\\cos(\\omega_d t) + B\\sin(\\omega_d t)\\right].\n\\end{equation}\\]</div>", "a[href=\"#modelo-matematico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo Matem\u00e1tico<a class=\"headerlink\" href=\"#modelo-matematico\" title=\"Link to this heading\">#</a></h2><h3>Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#balance-de-energia\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Tipos de soluci\u00f3n seg\u00fan la raz\u00f3n de amortiguamiento<a class=\"headerlink\" href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\" title=\"Link to this heading\">#</a></h2><h3>Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-e0b68e01-9a33-4400-afcf-3d8a94ab7159\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-e0b68e01-9a33-4400-afcf-3d8a94ab7159\">\n\\[\\begin{equation}\n x(t) = (A + Bt)e^{-\\omega_n t}.\n\\end{equation}\\]</div>", "a[href=\"#sistema-sobreamortiguado-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema sobreamortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta &gt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-sobreamortiguado-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Carga de datos experimentales y preparaci\u00f3n para el modelado conformable<a class=\"headerlink\" href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#ecuacion-diferencial-gobernante\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#equation-7597ace9-44a4-4a3b-b04d-e6e49b5ba0a1\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-7597ace9-44a4-4a3b-b04d-e6e49b5ba0a1\">\n\\[\\begin{equation}\n \\omega_n = \\sqrt{\\frac{k}{m}} \\quad \\text{[rad/s]}.\n\\end{equation}\\]</div>", "a[href=\"#optimizacion-multietapa\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Optimizaci\u00f3n multietapa<a class=\"headerlink\" href=\"#optimizacion-multietapa\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#funcion-objetivo-para-realizar-la-optimizacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-cb777aae-6843-4019-9d96-56f660d1246e\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-cb777aae-6843-4019-9d96-56f660d1246e\">\n\\[\\begin{equation}\n \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ f(t) = \\frac{1}{\\sigma^{1-\\alpha}} t^{1-\\alpha} \\frac{df}{dt},\n\\end{equation}\\]</div>", "a[href=\"#equation-fda095f9-edb1-4d2e-a54c-a6999bbac7e1\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-fda095f9-edb1-4d2e-a54c-a6999bbac7e1\">\n\\[\\begin{equation}\n x(t) = A\\cos(\\omega_n t) + B\\sin(\\omega_n t).\n\\end{equation}\\]</div>", "a[href=\"#ejemplo-de-parametros-de-simulacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ejemplo de Par\u00e1metros de Simulaci\u00f3n<a class=\"headerlink\" href=\"#ejemplo-de-parametros-de-simulacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#modelo-clasico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#componentes-de-fuerza\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Componentes de Fuerza<a class=\"headerlink\" href=\"#componentes-de-fuerza\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#perfil-de-verosimilitud-para-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Perfil de verosimilitud para <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#perfil-de-verosimilitud-para-sigma\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-4b0858a5-230f-4f55-86b1-7230110c482a\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-4b0858a5-230f-4f55-86b1-7230110c482a\">\n\\[\\begin{equation}\n E(t) = \\underbrace{\\frac{1}{2}m\\dot{x}^2}_{\\text{Cin\u00e9tica}} + \\underbrace{\\frac{1}{2}kx^2}_{\\text{Potencial}} + \\underbrace{\\int_0^t c\\dot{x}^2\\,dt}_{\\text{Disipada}}\n\\end{equation}\\]</div>", "a[href=\"#sistema-no-amortiguado-zeta-0\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n F\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><h3>Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#sistema-subamortiguado-0-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema subamortiguado (<span class=\"math notranslate nohighlight\">\\(0 &lt; \\zeta &lt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-subamortiguado-0-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Graficaci\u00f3n del ajuste optimizado vs. datos sint\u00e9ticos<a class=\"headerlink\" href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-440a5367-32f4-4c26-970e-32ceb80751d0\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-440a5367-32f4-4c26-970e-32ceb80751d0\">\n\\[\\begin{equation}\n \\lambda_{1,2} = -\\frac{c}{2m} \\pm \\sqrt{\\left(\\frac{c}{2m}\\right)^2 - \\frac{k}{m}}.\n\\end{equation}\\]</div>", "a[href=\"#modelo-conformable-con-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-sigma\" title=\"Link to this heading\">#</a></h2><h3>Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-2f8b9c38-04b9-4e77-8460-e727c42946b3\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-2f8b9c38-04b9-4e77-8460-e727c42946b3\">\n\\[\\begin{equation}\n m\\frac{d^2x}{dt^2} + c\\frac{dx}{dt} + kx = 0,\n\\end{equation}\\]</div>", "a[href=\"#sistema-masa-resorte-amortiguador\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador\" title=\"Link to this heading\">#</a></h1><p>Un <strong>sistema masa resorte amortiguador</strong> consta de tres componentes esenciales</p>", "a[href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador (sobreamortiguado)<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\" title=\"Link to this heading\">#</a></h1><h2>Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#parametros-adimensionales\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e1metros adimensionales<a class=\"headerlink\" href=\"#parametros-adimensionales\" title=\"Link to this heading\">#</a></h3><p><strong>Frecuencia Natural</strong></p>", "a[href=\"#ecuacion-caracteristica-del-sistema\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n caracter\u00edstica del sistema<a class=\"headerlink\" href=\"#ecuacion-caracteristica-del-sistema\" title=\"Link to this heading\">#</a></h3><p>Al sustituir <span class=\"math notranslate nohighlight\">\\(x(t) = e^{\\lambda t}\\)</span> se obtiene:</p>", "a[href=\"#obtencion-de-datos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obtenci\u00f3n de datos<a class=\"headerlink\" href=\"#obtencion-de-datos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-58cc1cae-1f31-4764-88f9-aca442427c08\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-58cc1cae-1f31-4764-88f9-aca442427c08\">\n\\[\\begin{equation}\n \\zeta = \\frac{c}{2\\sqrt{km}}.\n\\end{equation}\\]</div>", "a[href=\"#sistema-con-amortiguamiento-critico-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema con amortiguamiento cr\u00edtico (<span class=\"math notranslate nohighlight\">\\(\\zeta = 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-con-amortiguamiento-critico-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-9ddad0ce-1bd2-4260-b044-2bb2bcf33d63\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-9ddad0ce-1bd2-4260-b044-2bb2bcf33d63\">\n\\[\\begin{equation}\n x(t) = Ae^{\\lambda_1 t} + Be^{\\lambda_2 t}.\n\\end{equation}\\]</div>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
